/** Compact hero display for public stats (e.g. 7, 50+, 1.2k+, 8k+). Omits “+” under 100 so early-stage totals stay readable. */
function formatLandingPublicStat(n) {
  if (n == null || !Number.isFinite(Number(n))) return "—";
  const x = Math.max(0, Math.floor(Number(n)));
  if (x < 1000) return x <= 99 ? String(x) : `${x}+`;
  const wholeK = Math.floor(x / 1000);
  const remainder = x % 1000;
  if (remainder === 0 || wholeK >= 10) return `${wholeK}k+`;
  const tenths = Math.floor(x / 100) / 10;
  const s = Number.isInteger(tenths) ? String(tenths) : tenths.toFixed(1).replace(/\.0$/, "");
  return `${s}k+`;
}

/** Best-effort recency for ordering “unseen” pending rows (API field names vary). */
function orderRowSortMs(o) {
  const raw = o?.updatedAt ?? o?.updated_at ?? o?.createdAt ?? o?.created_at ?? 0;
  const t = new Date(raw).getTime();
  return Number.isFinite(t) ? t : 0;
}

const GOOGLE_CLIENT_ID = import.meta.env.VITE_GOOGLE_CLIENT_ID || "";
const COMMUNITY_MEMBERSHIP_KEY_PREFIX = "community_membership_v1:";
/** Set when the user taps Join on a shop; profile+address matching alone misses sparse profiles. */
const COMMUNITY_JOINED_SHOP_ID_KEY_PREFIX = "community_joined_shop_id_v1:";

function readJoinedShopCommunityId(userId) {
  if (typeof window === "undefined" || !userId) return "";
  try {
    return String(localStorage.getItem(`${COMMUNITY_JOINED_SHOP_ID_KEY_PREFIX}${userId}`) || "").trim();
  } catch {
    return "";
  }
}

function writeJoinedShopCommunityId(userId, communityId) {
  if (typeof window === "undefined" || !userId) return;
  try {
    const cid = String(communityId || "").trim();
    if (cid) localStorage.setItem(`${COMMUNITY_JOINED_SHOP_ID_KEY_PREFIX}${userId}`, cid);
    else localStorage.removeItem(`${COMMUNITY_JOINED_SHOP_ID_KEY_PREFIX}${userId}`);
  } catch {
    /* ignore */
  }
}

/** Keep in sync with server `MAX_LISTINGS_LIMIT` in `listListings`. */
const LISTINGS_API_PAGE_SIZE = 60;

/**
 * Fetches all pages of `GET /listings` for a given query (avoids the default 24-item cap).
 * De-dupes by listing `id` across pages.
 */
async function fetchAllListingsPages(token, baseQs) {
  const qsBase =
    typeof baseQs === "string"
      ? new URLSearchParams(baseQs)
      : baseQs instanceof URLSearchParams
        ? baseQs
        : new URLSearchParams(baseQs);
  const all = [];
  const seen = new Set();
  let offset = 0;
  for (;;) {
    const qs = new URLSearchParams(qsBase);
    qs.set("limit", String(LISTINGS_API_PAGE_SIZE));
    qs.set("offset", String(offset));
    const data = await apiRequest(`/listings?${qs.toString()}`, { token });
    const batch = Array.isArray(data?.listings) ? data.listings : [];
    for (const row of batch) {
      const id = String(row?.id ?? "");
      if (!id || seen.has(id)) continue;
      seen.add(id);
      all.push(row);
    }
    const pageHasMore = Boolean(data?.page?.hasMore);
    if (!pageHasMore || batch.length === 0) break;
    offset += batch.length;
  }
  return all;
}

function listingPriceCents(l) {
  if (Number.isFinite(Number(l?.priceCents))) return Math.max(0, Number(l.priceCents));
  const pesos = Number(l?.pricePesos);
  if (Number.isFinite(pesos)) return Math.max(0, Math.round(pesos * 100));
  return 0;
}

