    const tab = String(ordersStatusTab || "");
    const storageTabs = expandOrdersStatusTabToStorageKeys(tab);
    const map = ordersTabBadgeIdsByTab || {};
    const merged = new Set();
    storageTabs.forEach((t) => {
      (map[t] || []).forEach((id) => {
        const s = String(id || "");
        if (s) merged.add(s);
      });
    });
    return [...merged];
