    const source = commerceAllHubRole === "seller" ? bookingHubSellerOrders : bookingHubBuyerOrders;
    const totalInTab = (source || []).filter(
      (o) => orderIsServiceListingBooking(o) && orderMatchesBookingStatusTab(o.status, "history"),
    ).length;
